function solve(nums) {
    // 1. Collect G, the set of unique values in nums.
    const uniqueNums = new Set(nums);

    // 2. Map to store the minimum reachable value for each unique number.
    // Initialize minimum reachable value for g to be g itself.
    const minReachable = new Map();
    for (const g of uniqueNums) {
        minReachable.set(g, g);
    }

    // Convert set to array for iteration
    const G = Array.from(uniqueNums).sort((a, b) => a - b);

    // 3. Iterate through all g in G and find the smallest divisor present in G.
    // We iterate in increasing order of G to potentially benefit from earlier calculations, 
    // though the divisor method ensures correctness regardless of order, as we check all divisors.

    for (const g of G) {
        let currentMin = g;

        // Check for proper divisors d < g
        for (let d = 1; d * d <= g; d++) {
            if (g % d === 0) {
                // Check divisor d
                if (uniqueNums.has(d)) {
                    currentMin = Math.min(currentMin, d);
                }

                // Check complementary divisor g/d
                const d_complement = g / d;
                if (d_complement < g && uniqueNums.has(d_complement)) {
                    currentMin = Math.min(currentMin, d_complement);
                }
            }
        }

        minReachable.set(g, currentMin);
    }

    // 4. Calculate the final sum.
    let totalSum = 0;
    for (const num of nums) {
        totalSum += minReachable.get(num);
    }

    return totalSum;
}

