use std::collections::{HashMap, HashSet};

fn solve(nums: Vec<i64>) -> i64 {
    // 1. Collect unique numbers S.
    let unique_nums_set: HashSet<i64> = nums.iter().cloned().collect();

    // Convert to sorted vector for DP iteration (s_i increasing)
    let mut s_sorted: Vec<i64> = unique_nums_set.into_iter().collect();
    s_sorted.sort_unstable();

    // min_reachable maps g in S to m(g), the minimum reachable value for g.
    let mut min_reachable: HashMap<i64, i64> = HashMap::new();

    // 2. DP calculation: Iterate through s_i in increasing order
    for &s_i in s_sorted.iter() {
        // Initialize m(s_i) = s_i
        let mut current_min = s_i;

        // Find all proper divisors d of s_i. O(sqrt(s_i)).
        let limit = (s_i as f64).sqrt() as i64;

        for d in 1..=limit {
            if s_i % d == 0 {
                // Check divisor d
                // d must be smaller than s_i and present in S
                if d < s_i && unique_nums_set.contains(&d) {
                    // d is in S, and m(d) must have been calculated since d < s_i.
                    let m_d = *min_reachable.get(&d).expect("d must be in S and have been processed");
                    current_min = current_min.min(m_d);
                }

                // Check complementary divisor d_complement = s_i / d
                let d_complement = s_i / d;

                // d_complement must be a proper divisor (d_complement < s_i) 
                // and present in S, and not equal to d (to avoid redundant calculation if s_i is a perfect square)
                if d_complement < s_i && d_complement != d && unique_nums_set.contains(&d_complement) {
                    // d_complement is in S, and m(d_complement) must have been calculated since d_complement < s_i.
                    let m_d_comp = *min_reachable.get(&d_complement).expect("d_complement must be in S and have been processed");
                    current_min = current_min.min(m_d_comp);
                }
            }
        }

        min_reachable.insert(s_i, current_min);
    }

    // 3. Calculate the final sum.
    let mut total_sum = 0i64;
    for num in nums.iter() {
        // Look up the minimum reachable value for the original element.
        let m_num = *min_reachable.get(num).expect("Original number must be in min_reachable");
        total_sum += m_num;
    }

    total_sum
}

