fn solve(nums: Vec<i64>) -> i64 {
    const_MAX_VAL: usize = 100000;

    let mut is_present = vec![false; const_MAX_VAL + 1];
    let mut max_n: usize = 0;

    for &n in nums.iter() {
        let val = n as usize;
        if val <= const_MAX_VAL {
            is_present[val] = true;
            if val > max_n {
                max_n = val;
            }
        }
    }

    let mut min_reachable = vec![0i64; const_MAX_VAL + 1];

    for g_usize in 1..=max_n {
        if is_present[g_usize] {
            let g = g_usize as i64;
            let mut current_min = g;

            let mut d = 1;
            while d * d <= g_usize {
                if g_usize % d == 0 {
                    // Check divisor d
                    if is_present[d] {
                        current_min = current_min.min(d as i64);
                    }

                    // Check complementary divisor g/d
                    let d_complement_usize = g_usize / d;
                    if d_complement_usize < g_usize {
                         if is_present[d_complement_usize] {
                            let d_complement = d_complement_usize as i64;
                            current_min = current_min.min(d_complement);
                        }
                    }
                }
                d += 1;
            }
            min_reachable[g_usize] = current_min;
        }
    }

    let mut total_sum = 0i64;
    for &n in nums.iter() {
        let val = n as usize;
        total_sum += min_reachable[val];
    }

    total_sum
}

